+  transition: left var(--duration-normal) var(--ease-out);
+  backdrop-filter: blur(6px);
+}
+
+.translation-viz__cards {
+  display: grid;
+  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
+  gap: var(--space-2);
+}
+
+.translation-viz__card {
+  padding: var(--space-2);
+  border: 1px solid var(--color-border-subtle);
+  border-radius: var(--radius-md);
+  background: var(--color-background);
+}
+
+.translation-viz__card .label {
+  color: var(--color-text-muted);
+  font-size: var(--text-xs);
+  text-transform: uppercase;
+  letter-spacing: 0.04em;
+}
+
+.translation-viz__card .value {
+  font-weight: var(--font-semibold);
+  color: var(--color-text);
+  margin-top: 4px;
+}
+
+.translation-viz__card .hint {
+  color: var(--color-text-dim);
+  font-size: var(--text-xs);
+  margin-top: 4px;
+}
+
+.translation-viz__chain {
+  border: 1px dashed var(--color-border-subtle);
+  border-radius: var(--radius-lg);
+  padding: var(--space-3);
+  background: var(--color-background-alt);
+  display: flex;
+  flex-direction: column;
+  gap: var(--space-2);
+}
+
+.translation-viz__chain-label {
+  font-size: var(--text-sm);
+  color: var(--color-text-muted);
+  text-transform: uppercase;
+  letter-spacing: 0.05em;
+}
+
+.translation-viz__chain-track {
+  display: flex;
+  flex-wrap: wrap;
+  gap: var(--space-2);
+  align-items: center;
+  min-height: 38px;
+}
+
+.translation-viz__chain-aa {
+  padding: 6px 10px;
+  border-radius: var(--radius-md);
+  font-weight: var(--font-semibold);
+  box-shadow: var(--shadow-sm);
+}
+
+@media (max-width: 960px) {
+  .translation-viz__panel {
+    grid-template-columns: 1fr;
+  }
+
+  .translation-viz__header {
+    flex-direction: column;
+    align-items: flex-start;
+  }
+}
